import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const PostProductPage = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1); // 1: Chọn danh mục, 2: Điền thông tin
  const [selectedCat, setSelectedCat] = useState(null);

  // Dữ liệu Form chung
  const [formData, setFormData] = useState({
    name: '', price: '', image: '', description: '', location: 'TP. Hồ Chí Minh'
  });
  
  // Dữ liệu chi tiết riêng
  const [details, setDetails] = useState({});

  // Cấu hình danh mục
  const categories = [
    { 
      id: 'bds', name: 'Bất động sản', icon: '🏠',
      questions: [
        { key: 'area', label: 'Diện tích (m2)', type: 'number' },
        { key: 'bedrooms', label: 'Số phòng ngủ', type: 'number' },
        { key: 'direction', label: 'Hướng nhà', type: 'text' }
      ]
    },
    { 
      id: 'xe', name: 'Xe cộ', icon: '🛵',
      questions: [
        { key: 'brand', label: 'Hãng xe', type: 'text' },
        { key: 'year', label: 'Năm sản xuất', type: 'number' },
        { key: 'km', label: 'Số KM đã đi', type: 'number' }
      ]
    },
    { 
      id: 'dientu', name: 'Đồ điện tử', icon: '📱',
      questions: [
        { key: 'brand', label: 'Hãng sản xuất', type: 'text' },
        { key: 'warranty', label: 'Bảo hành (tháng)', type: 'number' },
        { key: 'color', label: 'Màu sắc', type: 'text' }
      ]
    },
    { 
      id: 'vieclam', name: 'Việc làm', icon: '💼',
      questions: [
        { key: 'salary', label: 'Mức lương', type: 'text' },
        { key: 'position', label: 'Vị trí công việc', type: 'text' },
        { key: 'type', label: 'Hình thức (Fulltime/Parttime)', type: 'text' }
      ]
    },
    { 
      id: 'dogiadung', name: 'Đồ gia dụng', icon: '🪑',
      questions: [
        { key: 'type', label: 'Loại đồ dùng (Bàn, Ghế, Tủ...)', type: 'text' },
        { key: 'material', label: 'Chất liệu (Gỗ, Nhựa, Inox...)', type: 'text' },
        { key: 'status', label: 'Tình trạng ngoại hình (%)', type: 'number' }
      ]
    },
    { 
      id: 'thucung', name: 'Thú cưng', icon: '🐶',
      questions: [
        { key: 'breed', label: 'Giống loài', type: 'text' },
        { key: 'age', label: 'Độ tuổi (Tháng)', type: 'number' },
        { key: 'vaccine', label: 'Đã tiêm phòng chưa?', type: 'text' }
      ] 
    }, 
  ];

  // Xử lý chọn danh mục
  const handleSelectCategory = (cat) => {
    setSelectedCat(cat);
    setStep(2);
    setDetails({});
  };

  // Xử lý gửi form
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:5000/api/products', {
        ...formData,
        category: selectedCat.name,
        details: details
      });
      alert('Đăng tin thành công!');
      navigate('/');
    } catch (error) {
      alert('Lỗi: ' + (error.response?.data?.message || 'Không thể đăng tin'));
    }
  };

  return (
    <div className="container py-4" style={{maxWidth: '800px'}}>
      
      {/* --- MỚI THÊM: LOGO QUAY VỀ TRANG CHỦ --- */}
      <header className="d-flex align-items-center mb-4">
         <h2 
            className="fw-bold text-chotot m-0" 
            style={{cursor: 'pointer'}} 
            onClick={() => navigate('/')}
            title="Quay về trang chủ"
         >
            HaiHand
         </h2>
         <span className="ms-3 text-muted border-start ps-3">Đăng tin</span>
         
         {/* Nút đóng nhỏ ở góc phải cho tiện */}
         <button className="btn btn-close ms-auto" onClick={() => navigate('/')}></button>
      </header>

      {/* --- BƯỚC 1: CHỌN DANH MỤC --- */}
      {step === 1 && (
        <div className="card shadow border-0 animate__animated animate__fadeInUp">
           <div className="card-header bg-white border-bottom-0 pt-4 pb-0 text-center">
              <h4 className="fw-bold text-primary">Bạn muốn đăng bán gì hôm nay?</h4>
              <p className="text-muted">Chọn đúng danh mục giúp người mua tìm thấy bạn nhanh hơn gấp 5 lần!</p>
           </div>
           <div className="card-body p-4">
              <div className="row g-3">
                 {categories.map(cat => (
                    <div className="col-6 col-md-4" key={cat.id}>
                       <div 
                          className="card h-100 text-center py-4 border-0 shadow-sm category-hover" 
                          style={{cursor: 'pointer', backgroundColor: '#f8f9fa', transition: 'all 0.2s'}}
                          onClick={() => handleSelectCategory(cat)}
                          onMouseOver={(e) => e.currentTarget.style.transform = 'translateY(-5px)'}
                          onMouseOut={(e) => e.currentTarget.style.transform = 'translateY(0)'}
                        >
                          <div style={{fontSize: '45px', marginBottom: '10px'}}>{cat.icon}</div>
                          <div className="fw-bold fs-5">{cat.name}</div>
                       </div>
                    </div>
                 ))}
              </div>
           </div>
        </div>
      )}

      {/* --- BƯỚC 2: ĐIỀN THÔNG TIN --- */}
      {step === 2 && (
        <div className="card shadow border-0 animate__animated animate__fadeIn">
          <div className="card-header bg-chotot text-dark d-flex align-items-center py-3">
            <button className="btn btn-sm btn-outline-dark me-3 fw-bold" onClick={() => setStep(1)}>⬅ Quay lại</button>
            <h5 className="mb-0 fw-bold flex-grow-1 text-center pe-5">Đăng tin: {selectedCat.name}</h5>
          </div>
          <div className="card-body p-4">
            <form onSubmit={handleSubmit}>
              
              {/* 1. THÔNG TIN CƠ BẢN */}
              <h6 className="fw-bold text-primary mb-3 border-bottom pb-2">1. Thông tin chung</h6>
              <div className="mb-3">
                <label className="form-label fw-bold">Tiêu đề tin đăng <span className="text-danger">*</span></label>
                <input type="text" className="form-control" required 
                  onChange={(e) => setFormData({...formData, name: e.target.value})} 
                  placeholder={`Ví dụ: Bán ${selectedCat.name} giá rẻ...`}
                />
              </div>
              
              <div className="row">
                 <div className="col-md-6 mb-3">
                    <label className="form-label fw-bold">Giá bán (VNĐ) <span className="text-danger">*</span></label>
                    <input type="number" className="form-control" required 
                      onChange={(e) => setFormData({...formData, price: e.target.value})} 
                      placeholder="Nhập số tiền..."
                    />
                 </div>
                 <div className="col-md-6 mb-3">
                    <label className="form-label fw-bold">Khu vực bán</label>
                    <select className="form-select" 
                      onChange={(e) => setFormData({...formData, location: e.target.value})}
                    >
                       <option>TP. Hồ Chí Minh</option>
                       <option>Hà Nội</option>
                       <option>Đà Nẵng</option>
                       <option>Cần Thơ</option>
                       <option>Hải Phòng</option>
                       <option>Đồng Nai</option>
                    </select>
                 </div>
              </div>

              {/* 2. THÔNG TIN RIÊNG */}
              {selectedCat.questions.length > 0 && (
                <div className="bg-light p-3 rounded mb-4 border border-warning">
                  <h6 className="fw-bold text-dark mb-3">2. Chi tiết về {selectedCat.name}</h6>
                  <div className="row">
                    {selectedCat.questions.map(q => (
                       <div className="col-md-6 mb-3" key={q.key}>
                          <label className="form-label">{q.label}</label>
                          <input 
                            type={q.type} 
                            className="form-control"
                            required
                            placeholder="Nhập thông tin..."
                            onChange={(e) => setDetails({...details, [q.key]: e.target.value})}
                          />
                       </div>
                    ))}
                  </div>
                </div>
              )}

              {/* 3. HÌNH ẢNH & MÔ TẢ */}
              <h6 className="fw-bold text-primary mb-3 border-bottom pb-2">3. Hình ảnh & Mô tả</h6>
              <div className="mb-3">
                <label className="form-label fw-bold">Link Hình ảnh <span className="text-danger">*</span></label>
                <input type="text" className="form-control" required
                  onChange={(e) => setFormData({...formData, image: e.target.value})}
                  placeholder="Dán link ảnh sản phẩm vào đây..."
                />
              </div>
              {formData.image && (
                <div className="mb-3 text-center bg-light p-2 rounded">
                    <img src={formData.image} alt="Preview" className="rounded shadow-sm" style={{maxHeight: '200px', maxWidth: '100%'}} />
                </div>
              )}

              <div className="mb-4">
                <label className="form-label fw-bold">Mô tả chi tiết</label>
                <textarea className="form-control" rows="5" required
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  placeholder="Mô tả chi tiết về tình trạng, xuất xứ, lý do bán..."
                ></textarea>
              </div>

              <button type="submit" className="btn btn-chotot w-100 fw-bold py-3 fs-5 shadow-sm text-uppercase">
                Đăng tin ngay
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default PostProductPage;
